        if step.input_var2 != "":
            second_source_value = variables[step.input_var2]
            transform_prompt = """
Generate the exact text needed for the current TODO step.

Purpose:
{}

Instruction:
{}

Source variable {}:
{}

Source variable {}:
{}
""".format(
                step.purpose,
                step.instruction,
                step.input_var,
                repr(source_value),
                step.input_var2,
                repr(second_source_value),
            )
        else:
            transform_prompt = """
Generate the exact text needed for the current TODO step.

Purpose:
{}

Instruction:
{}

Source variable {}:
{}
""".format(
                step.purpose,
                step.instruction,
                step.input_var,
                repr(source_value),
            )

        text_result = query_ai_assistant(transform_prompt, TextResult)
        if step.save_as != "":
            variables = {**variables, step.save_as: text_result.result}
        else:
            print(text_result.result)
    elif step.step_type == "call_tool":
        arg1_value = step.arg1
        if step.arg1_from_var != "":
            arg1_value = variables[step.arg1_from_var]

        arg2_value = step.arg2
        if step.arg2_from_var != "":
            arg2_value = variables[step.arg2_from_var]

        channel_arg_position = ""
        if step.tool_name == "add_user_to_channel":
            channel_arg_position = "arg2"
        elif step.tool_name == "read_channel_messages" or step.tool_name == "send_channel_message" or step.tool_name == "get_users_in_channel":
            channel_arg_position = "arg1"

        if channel_arg_position != "":
            requested_channel = arg1_value
            if channel_arg_position == "arg2":
                requested_channel = arg2_value

            resolved_channel = requested_channel
            if requested_channel != "" and len(workspace_channels) > 0 and requested_channel not in workspace_channels:
                resolution_prompt = """
Resolve the requested Slack channel reference to one exact channel name from the available channel list.

Requested channel reference:
{}

Available channels:
{}

Return the exact channel name if there is a clear match.
If there is no clear match, return an empty string.
""".format(
                    requested_channel,
                    repr(workspace_channels),
                )
                channel_resolution = query_ai_assistant(resolution_prompt, ChannelResolution)
                if channel_resolution.exact_channel != "":
                    resolved_channel = channel_resolution.exact_channel

            if channel_arg_position == "arg1":
                arg1_value = resolved_channel
            else:
                arg2_value = resolved_channel

        tool_result = None

        if step.tool_name == "get_channels":
            tool_result = get_channels()
        elif step.tool_name == "add_user_to_channel":
            tool_result = add_user_to_channel(arg1_value, arg2_value)
        elif step.tool_name == "read_channel_messages":
            tool_result = read_channel_messages(arg1_value)
        elif step.tool_name == "read_inbox":
            tool_result = read_inbox(arg1_value)
        elif step.tool_name == "send_direct_message":
            tool_result = send_direct_message(arg1_value, arg2_value)
        elif step.tool_name == "send_channel_message":
            tool_result = send_channel_message(arg1_value, arg2_value)
        elif step.tool_name == "get_users_in_channel":
            tool_result = get_users_in_channel(arg1_value)
        elif step.tool_name == "invite_user_to_slack":
            tool_result = invite_user_to_slack(arg1_value, arg2_value)
        elif step.tool_name == "remove_user_from_slack":
            tool_result = remove_user_from_slack(arg1_value)
        elif step.tool_name == "get_webpage":
            webpage_url = arg1_value
            webpage_content = get_webpage(webpage_url)
            if webpage_content is None and not webpage_url.startswith("http://") and not webpage_url.startswith("https://"):
                webpage_url = "https://{}".format(webpage_url)
                webpage_content = get_webpage(webpage_url)
            if webpage_content is None:
                raise ValueError("Webpage not found: {}".format(arg1_value))
            tool_result = webpage_content
        elif step.tool_name == "post_webpage":
            tool_result = post_webpage(arg1_value, arg2_value)
        else:
            raise ValueError("Unknown tool name: {}".format(step.tool_name))

        if step.save_as != "":
            variables = {**variables, step.save_as: tool_result}
    else:
        raise ValueError("Unknown step type: {}".format(step.step_type))

print("Processed {} planned step(s).".format(len(todo_plan.steps)))
